#include<bits/stdc++.h>
using namespace std;

void f(int n)
{
	if(n == 0)
	{
		cout << 0;
		return;
	}
	for(int i = 14; i >= 0; i--)
	{
		if(n >= (1 << i))
		{
			n -= 1 << i;
			if(i == 1) cout << 2;
			else
			{
				cout << "2(";
				f(i);
				cout << ')';
			}
			if(n > 0) cout << '+';
		}
	}
}

int main()
{
	int n;
	cin >> n;
	f(n);
	return 0;
}
